import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AIMode, Message, ChatSession, MessagePart } from './types';
import { IconBolt, IconBrain, IconSearch, IconImage, IconSend, IconPlus, IconTrash, IconHistory } from './components/Icons';
import { GeminiService } from './services/geminiService';
import { APP_NAME, APP_SUBTITLE } from './constants';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FAST);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  // Load from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('gemini_sessions');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setActiveSessionId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load sessions", e);
      }
    }
  }, []);

  // Save to localStorage
  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('gemini_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeSession?.messages, isLoading]);

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
  };

  const deleteSession = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSessions(prev => {
      const filtered = prev.filter(s => s.id !== id);
      if (activeSessionId === id) {
        setActiveSessionId(filtered.length > 0 ? filtered[0].id : null);
      }
      return filtered;
    });
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isLoading) return;

    let currentSessionId = activeSessionId;
    if (!currentSessionId) {
      const newSession: ChatSession = {
        id: Date.now().toString(),
        title: inputText.slice(0, 30),
        messages: [],
        createdAt: Date.now(),
      };
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newSession.id);
      currentSessionId = newSession.id;
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      parts: [{ text: inputText }],
      mode,
    };

    setSessions(prev => prev.map(s => 
      s.id === currentSessionId 
        ? { ...s, messages: [...s.messages, userMessage], title: s.messages.length === 0 ? inputText.slice(0, 30) : s.title } 
        : s
    ));

    const prompt = inputText;
    setInputText('');
    setIsLoading(true);

    try {
      if (mode === AIMode.IMAGE) {
        // Nano Banana Pro requires API key check
        const isKeySelected = await GeminiService.checkApiKeySelection();
        if (!isKeySelected) {
          await GeminiService.requestApiKeySelection();
        }

        const imageUrl = await GeminiService.generateImage(prompt);
        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: "Generasi Gambar Pro Berhasil:", image: imageUrl }],
          mode,
        };
        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));
      } else {
        const history = activeSession?.messages.map(m => ({
          role: m.role,
          parts: m.parts.filter(p => p.text).map(p => ({ text: p.text! }))
        })) || [];

        const stream = GeminiService.streamText(prompt, mode, history);

        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: '' }],
          mode,
          isThinking: mode === AIMode.THINKING,
          thinking: '',
          groundingLinks: []
        };

        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));

        let fullText = '';
        let groundingChunks: any[] = [];

        for await (const chunk of stream) {
          if (chunk.text) {
            fullText += chunk.text;
          }

          const grounding = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
          if (grounding) groundingChunks = [...groundingChunks, ...grounding];

          setSessions(prev => prev.map(s => 
            s.id === currentSessionId ? {
              ...s,
              messages: s.messages.map(m => m.id === modelMessage.id ? {
                ...m,
                parts: [{ text: fullText }],
                groundingLinks: groundingChunks,
                isThinking: false,
              } : m)
            } : s
          ));
        }
      }
    } catch (error: any) {
      console.error(error);
      const errorMessage: Message = {
        id: (Date.now() + 2).toString(),
        role: 'model',
        parts: [{ text: `Error: ${error.message || 'Gagal terhubung ke Gemini API.'}` }],
      };
      setSessions(prev => prev.map(s => 
        s.id === currentSessionId ? { ...s, messages: [...s.messages, errorMessage] } : s
      ));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-zinc-200">
      {/* Sidebar */}
      <aside className={`${isSidebarOpen ? 'w-72' : 'w-0'} bg-zinc-950 border-r border-zinc-800 transition-all duration-300 flex flex-col overflow-hidden`}>
        <div className="p-4 flex flex-col h-full">
          <button 
            onClick={createNewSession}
            className="flex items-center gap-2 w-full p-3 bg-zinc-900 border border-zinc-800 rounded-xl hover:bg-zinc-800 transition-colors mb-6 text-sm font-medium"
          >
            <IconPlus className="w-4 h-4" /> New Chat
          </button>

          <div className="flex-1 overflow-y-auto space-y-1">
            <div className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2 px-2 flex items-center gap-2">
              <IconHistory className="w-3 h-3" /> History
            </div>
            {sessions.map(s => (
              <button
                key={s.id}
                onClick={() => setActiveSessionId(s.id)}
                // Added 'group' class to handle IconTrash hover and visibility correctly
                className={`group flex items-center justify-between gap-2 w-full p-3 rounded-lg text-sm text-left transition-all ${activeSessionId === s.id ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-900 text-zinc-400'}`}
              >
                <span className="truncate flex-1">{s.title}</span>
                <IconTrash 
                  className="w-4 h-4 opacity-0 group-hover:opacity-100 hover:text-red-500" 
                  onClick={(e) => deleteSession(s.id, e)} 
                />
              </button>
            ))}
          </div>

          <div className="mt-auto pt-4 border-t border-zinc-900">
            <div className="flex items-center gap-3 p-2">
              <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center font-bold text-xs">
                G3
              </div>
              <div className="text-xs">
                <p className="font-semibold text-zinc-200">Gemini 3 Pro</p>
                <p className="text-zinc-500">Fast 2.5 Engine</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col bg-zinc-950 relative">
        {/* Header */}
        <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/50 backdrop-blur-md z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-zinc-900 rounded-lg text-zinc-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" x2="21" y1="6" y2="6"/><line x1="3" x2="21" y1="12" y2="12"/><line x1="3" x2="21" y1="18" y2="18"/></svg>
            </button>
            <div className="flex items-center gap-2">
              <span className="font-bold text-lg bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">{APP_NAME}</span>
              <span className="text-xs bg-zinc-800 text-zinc-400 px-2 py-0.5 rounded-full uppercase tracking-tighter border border-zinc-700 font-mono">Ultra</span>
            </div>
          </div>

          <div className="flex items-center gap-1 bg-zinc-900 p-1 rounded-xl border border-zinc-800">
            {[
              { id: AIMode.FAST, icon: IconBolt, label: 'Fast' },
              { id: AIMode.THINKING, icon: IconBrain, label: 'Thinking' },
              { id: AIMode.SEARCH, icon: IconSearch, label: 'Search' },
              { id: AIMode.IMAGE, icon: IconImage, label: 'Image' },
            ].map(m => (
              <button
                key={m.id}
                onClick={() => setMode(m.id)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${mode === m.id ? 'bg-zinc-800 text-blue-400 shadow-lg border border-zinc-700' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                <m.icon className="w-3.5 h-3.5" />
                <span className="hidden sm:inline">{m.label}</span>
              </button>
            ))}
          </div>
        </header>

        {/* Chat Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-8 max-w-4xl mx-auto w-full pt-10">
          {!activeSession || activeSession.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 pt-20">
              <div className="w-20 h-20 rounded-3xl bg-gradient-to-br from-blue-600 to-purple-700 flex items-center justify-center shadow-2xl shadow-blue-900/20">
                <IconBrain className="w-10 h-10 text-white" />
              </div>
              <div>
                <h1 className="text-3xl font-bold text-white mb-2">Welcome to Gemini 3 Pro</h1>
                <p className="text-zinc-500 max-w-md mx-auto">Ultra-fast response, deep thinking capability, real-time web search, and pro HD image generation.</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 w-full max-w-lg">
                <button onClick={() => setInputText("Analisis masa depan AI dalam 5 tahun")} className="p-4 bg-zinc-900/50 border border-zinc-800 rounded-2xl hover:border-blue-500/50 transition-all text-left group">
                  <p className="text-xs text-blue-400 font-semibold mb-1">Deep Thinking</p>
                  <p className="text-sm text-zinc-300">"Analisis masa depan AI dalam 5 tahun ke depan..."</p>
                </button>
                <button onClick={() => setInputText("Buat gambar cyberpunk futuristic city HD Realistic")} className="p-4 bg-zinc-900/50 border border-zinc-800 rounded-2xl hover:border-purple-500/50 transition-all text-left group">
                  <p className="text-xs text-purple-400 font-semibold mb-1">Nano Banana Pro</p>
                  <p className="text-sm text-zinc-300">"Buat gambar cyberpunk futuristic city HD Realistic..."</p>
                </button>
              </div>
            </div>
          ) : (
            activeSession.messages.map((msg, i) => (
              <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                <div className={`max-w-[85%] sm:max-w-[75%] rounded-3xl p-4 sm:p-5 ${msg.role === 'user' ? 'bg-zinc-800 text-white' : 'bg-zinc-900 border border-zinc-800'} space-y-3`}>
                  {msg.isThinking && (
                    <div className="flex items-center gap-3 text-blue-400 text-sm font-mono animate-pulse">
                      <IconBrain className="w-4 h-4" />
                      <span>Thinking deeply...</span>
                    </div>
                  )}

                  {msg.parts.map((part, idx) => (
                    <div key={idx}>
                      {part.text && (
                        <div className="prose prose-invert max-w-none text-zinc-200 leading-relaxed whitespace-pre-wrap">
                          {part.text}
                        </div>
                      )}
                      {part.image && (
                        <div className="mt-4 overflow-hidden rounded-2xl border border-zinc-800 bg-black aspect-square group relative">
                          <img src={part.image} alt="Generated by AI" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" />
                          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-4">
                            <a href={part.image} download={`gemini-image-${Date.now()}.png`} className="text-xs bg-white text-black px-4 py-2 rounded-full font-bold">Download HD</a>
                          </div>
                        </div>
                      )}
                    </div>
                  ))}

                  {msg.groundingLinks && msg.groundingLinks.length > 0 && (
                    <div className="mt-4 pt-4 border-t border-zinc-800 space-y-2">
                      <p className="text-xs font-semibold text-zinc-500 uppercase flex items-center gap-1">
                        <IconSearch className="w-3 h-3" /> Sources
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {msg.groundingLinks.map((link, idx) => (
                          link.web && (
                            <a 
                              key={idx} 
                              href={link.web.uri} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="text-xs bg-zinc-800 hover:bg-zinc-700 text-blue-400 px-3 py-1 rounded-full border border-zinc-700 transition-colors"
                            >
                              {link.web.title || new URL(link.web.uri).hostname}
                            </a>
                          )
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Bar */}
        <div className="p-4 sm:p-6 bg-gradient-to-t from-zinc-950 via-zinc-950 to-transparent">
          <div className="max-w-4xl mx-auto relative group">
            <div className={`absolute -inset-0.5 bg-gradient-to-r ${mode === AIMode.THINKING ? 'from-blue-500 to-cyan-500' : mode === AIMode.IMAGE ? 'from-purple-500 to-pink-500' : 'from-zinc-700 to-zinc-600'} rounded-[24px] blur opacity-20 group-focus-within:opacity-40 transition duration-1000 group-hover:duration-200`}></div>
            <div className="relative flex items-end gap-2 bg-zinc-900 border border-zinc-800 p-2 pl-4 rounded-[22px] shadow-2xl">
              <textarea
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendMessage();
                  }
                }}
                placeholder={
                  mode === AIMode.IMAGE ? "Deskripsikan gambar HD yang ingin dibuat..." : 
                  mode === AIMode.THINKING ? "Berikan pertanyaan kompleks untuk analisis mendalam..." :
                  mode === AIMode.SEARCH ? "Cari informasi real-time dari internet..." :
                  "Ketik pesan Anda..."
                }
                className="flex-1 bg-transparent border-none focus:ring-0 text-zinc-200 placeholder-zinc-600 py-3 resize-none max-h-40 min-h-[44px]"
                rows={1}
                style={{ height: 'auto', minHeight: '44px' }}
              />
              <button
                onClick={handleSendMessage}
                disabled={!inputText.trim() || isLoading}
                className={`p-3 rounded-2xl transition-all ${!inputText.trim() || isLoading ? 'text-zinc-600 bg-zinc-800' : 'bg-blue-600 text-white hover:bg-blue-500 shadow-lg shadow-blue-900/20'}`}
              >
                {isLoading ? (
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <IconSend className="w-5 h-5" />
                )}
              </button>
            </div>
          </div>
          <p className="text-center text-[10px] text-zinc-600 mt-4 uppercase tracking-[0.2em]">
            Gemini 3 Pro • Fast 2.5 Engine • Nano Banana Pro HD
          </p>
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';

export const APP_NAME = "Gemini 3 Pro";
export const APP_SUBTITLE = "Ultra AI Workspace";

export const MODELS = {
  FLASH: 'gemini-3-flash-preview',
  PRO: 'gemini-3-pro-preview',
  IMAGE: 'gemini-3-pro-image-preview'
};

export const SYSTEM_INSTRUCTIONS = `You are Gemini 3 Pro Ultra, a state-of-the-art AI workspace. 
Depending on the user's selected mode:
- FAST: Provide lightning-quick, concise, and direct answers using the Flash engine.
- THINKING: Provide deep, analytical, and logical reasoning using the Pro Thinking engine.
- SEARCH: Use real-time web information via Google Search grounding to answer accurately.
- IMAGE (Nano Banana Pro): Generate high-definition, realistic, and artistic images based on user prompts.

Maintain a professional, helpful, and creative persona at all times.`;

import { GoogleGenAI, Type, GenerateContentResponse, GenerateContentParameters } from "@google/genai";
import { AIMode, MessagePart, GroundingChunk } from "../types";
import { MODELS, SYSTEM_INSTRUCTIONS } from "../constants";

export class GeminiService {
  private static getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async checkApiKeySelection(): Promise<boolean> {
    if (window.aistudio?.hasSelectedApiKey) {
      return await window.aistudio.hasSelectedApiKey();
    }
    return true; 
  }

  static async requestApiKeySelection() {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
    }
  }

  static async generateImage(prompt: string): Promise<string> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODELS.IMAGE,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    let imageUrl = '';
    const parts = response.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!imageUrl) throw new Error("No image data received from the model.");
    return imageUrl;
  }

  static async *streamText(
    prompt: string, 
    mode: AIMode, 
    history: { role: 'user' | 'model'; parts: { text: string }[] }[]
  ) {
    const ai = this.getAI();

    // Select model based on mode requirements
    // Gemini 3 Pro strictly requires thinking, while Flash allows disabling it for speed.
    const modelName = (mode === AIMode.FAST) ? MODELS.FLASH : MODELS.PRO;

    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTIONS,
      temperature: mode === AIMode.THINKING ? 1.0 : 0.7,
    };

    if (mode === AIMode.THINKING) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    } else if (mode === AIMode.FAST) {
      config.thinkingConfig = { thinkingBudget: 0 };
    }

    if (mode === AIMode.SEARCH) {
      config.tools = [{ googleSearch: {} }];
      // When using Search, we use the Pro model but let it decide thinking usage 
      // unless specifically overridden, but omitting it is safest for grounding.
    }

    const responseStream = await ai.models.generateContentStream({
      model: modelName,
      contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
      config: config
    });

    for await (const chunk of responseStream) {
      yield chunk;
    }
  }
}

