                    rows={1}
                    style={{ height: 'auto', minHeight: '44px' }}
                  />

                  <button
                    onClick={handleSendMessage}
                    disabled={(!inputText.trim() && !selectedImage) || isLoading}
                    className={`p-3 rounded-xl transition-all flex items-center justify-center min-w-[48px] ${(!inputText.trim() && !selectedImage) || isLoading ? 'text-zinc-600 bg-zinc-800' : 'bg-blue-600 text-white hover:bg-blue-500 shadow-lg shadow-blue-900/20 active:scale-95'}`}
                  >
