    <div className="flex h-screen overflow-hidden text-zinc-200">
      <aside className={`${isSidebarOpen ? 'w-72' : 'w-0'} bg-zinc-950 border-r border-zinc-800 transition-all duration-300 flex flex-col overflow-hidden`}>
        <div className="p-4 flex flex-col h-full">
          <button 
            onClick={createNewSession}
            className="flex items-center gap-2 w-full p-3 bg-zinc-900 border border-zinc-800 rounded-xl hover:bg-zinc-800 transition-colors mb-6 text-sm font-medium"
          >
            <IconPlus className="w-4 h-4" /> New Chat
          </button>

          <div className="flex-1 overflow-y-auto space-y-1">
            <div className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2 px-2 flex items-center gap-2">
              <IconHistory className="w-3 h-3" /> History
            </div>
            {sessions.map(s => (
              <button
                key={s.id}
                onClick={() => setActiveSessionId(s.id)}
                className={`group flex items-center justify-between gap-2 w-full p-3 rounded-lg text-sm text-left transition-all ${activeSessionId === s.id ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-900 text-zinc-400'}`}
              >
                <span className="truncate flex-1">{s.title}</span>
                <IconTrash 
                  className="w-4 h-4 opacity-0 group-hover:opacity-100 hover:text-red-500" 
                  onClick={(e) => deleteSession(s.id, e)} 
                />
              </button>
            ))}
          </div>

          <div className="mt-auto pt-4 border-t border-zinc-900">
            <div className="flex items-center gap-3 p-2">
              <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center font-bold text-xs">
                RA
              </div>
              <div className="text-xs">
                <p className="font-semibold text-zinc-200">RAFEN AI</p>
                <p className="text-zinc-500">Ultra Workspace</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col bg-zinc-950 relative">
        <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/50 backdrop-blur-md z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-zinc-900 rounded-lg text-zinc-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" x2="21" y1="6" y2="6"/><line x1="3" x2="21" y1="12" y2="12"/><line x1="3" x2="21" y1="18" y2="18"/></svg>
            </button>
            <div className="flex items-center gap-2">
              <span className="font-bold text-lg bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">{APP_NAME}</span>
              <span className="text-xs bg-zinc-800 text-zinc-400 px-2 py-0.5 rounded-full uppercase tracking-tighter border border-zinc-700 font-mono">Ultra</span>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 space-y-8 max-w-4xl mx-auto w-full pt-10 pb-40">
          {!activeSession || activeSession.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-6 pt-20">
