import { GoogleGenAI, Type, GenerateContentResponse, GenerateContentParameters } from "@google/genai";
import { AIMode, MessagePart, GroundingChunk } from "../types";
import { MODELS, SYSTEM_INSTRUCTIONS } from "../constants";

export class GeminiService {
  private static getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async checkApiKeySelection(): Promise<boolean> {
    if (window.aistudio?.hasSelectedApiKey) {
      return await window.aistudio.hasSelectedApiKey();
    }
    return true; 
  }

  static async requestApiKeySelection() {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
    }
  }

  static async generateImage(prompt: string): Promise<string> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODELS.IMAGE,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    let imageUrl = '';
    const parts = response.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!imageUrl) throw new Error("No image data received from the model.");
    return imageUrl;
  }

  static async generateSpeech(text: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: ['AUDIO'],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data received from TTS engine.");
    return base64Audio;
  }

  static async *streamText(
    prompt: string, 
    mode: AIMode, 
    history: { role: 'user' | 'model'; parts: { text: string }[] }[],
    imageB64?: string
  ) {
    const ai = this.getAI();

    const modelName = (mode === AIMode.FAST) ? MODELS.FLASH : MODELS.PRO;

    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTIONS,
      temperature: mode === AIMode.THINKING ? 1.0 : 0.7,
    };

    if (mode === AIMode.THINKING) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    } else if (mode === AIMode.FAST) {
      config.thinkingConfig = { thinkingBudget: 0 };
    }

    if (mode === AIMode.SEARCH) {
      config.tools = [{ googleSearch: {} }];
    }

    const currentParts: any[] = [{ text: prompt }];
    if (imageB64) {
      // Extract base64 data and mime type
      const match = imageB64.match(/^data:(image\/\w+);base64,(.+)$/);
      if (match) {
        currentParts.push({
          inlineData: {
            mimeType: match[1],
            data: match[2]
          }
        });
      }
    }

    const responseStream = await ai.models.generateContentStream({
      model: modelName,
      contents: [...history, { role: 'user', parts: currentParts }],
      config: config
    });

    for await (const chunk of responseStream) {
      yield chunk;
    }
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AIMode, Message, ChatSession, MessagePart } from './types';
import { IconBolt, IconBrain, IconSearch, IconImage, IconSend, IconPlus, IconTrash, IconHistory, IconClip, IconX, IconSpeaker } from './components/Icons';
import { GeminiService } from './services/geminiService';
import { APP_NAME, APP_SUBTITLE } from './constants';

// Audio Helpers
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FAST);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isSpeakingId, setIsSpeakingId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('gemini_sessions');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setActiveSessionId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load sessions", e);
      }
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('gemini_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeSession?.messages, isLoading]);

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setSelectedImage(null);
  };

  const deleteSession = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSessions(prev => {
      const filtered = prev.filter(s => s.id !== id);
      if (activeSessionId === id) {
        setActiveSessionId(filtered.length > 0 ? filtered[0].id : null);
      }
      return filtered;
    });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      setSelectedImage(event.target?.result as string);
    };
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const handlePlayTTS = async (messageId: string, text: string) => {
    if (isSpeakingId === messageId) {
      currentSourceRef.current?.stop();
      setIsSpeakingId(null);
      return;
    }

    try {
      setIsSpeakingId(messageId);
      const base64Audio = await GeminiService.generateSpeech(text);

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioContextRef.current;
      const bytes = decode(base64Audio);
      const audioBuffer = await decodeAudioData(bytes, ctx, 24000, 1);

      if (currentSourceRef.current) {
        currentSourceRef.current.stop();
      }

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setIsSpeakingId(null);

      currentSourceRef.current = source;
      source.start();
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeakingId(null);
    }
  };

  const handleSendMessage = async () => {
    if ((!inputText.trim() && !selectedImage) || isLoading) return;

    let currentSessionId = activeSessionId;
    if (!currentSessionId) {
      const newSession: ChatSession = {
        id: Date.now().toString(),
        title: inputText.slice(0, 30) || 'Image Analysis',
        messages: [],
        createdAt: Date.now(),
      };
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newSession.id);
      currentSessionId = newSession.id;
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      parts: [
        ...(selectedImage ? [{ image: selectedImage }] : []),
        { text: inputText }
      ],
      mode,
    };

    setSessions(prev => prev.map(s => 
      s.id === currentSessionId 
        ? { ...s, messages: [...s.messages, userMessage], title: s.messages.length === 0 ? (inputText.slice(0, 30) || 'Image Analysis') : s.title } 
        : s
    ));

    const prompt = inputText || "Tell me about this image.";
    const imageToSubmit = selectedImage;
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      if (mode === AIMode.IMAGE) {
        const isKeySelected = await GeminiService.checkApiKeySelection();
        if (!isKeySelected) {
          await GeminiService.requestApiKeySelection();
        }

        const imageUrl = await GeminiService.generateImage(prompt);
        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: "Generasi Gambar Pro Berhasil:", image: imageUrl }],
          mode,
