        const stream = GeminiService.streamText(prompt, mode, history, imageToSubmit || undefined);

        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: '' }],
          mode,
          isThinking: mode === AIMode.THINKING,
