import React from 'react';

export const APP_NAME = "RAFEN AI";
export const APP_SUBTITLE = "Ultra AI Workspace";

export const MODELS = {
  FLASH: 'gemini-3-flash-preview',
  PRO: 'gemini-3-pro-preview',
  IMAGE: 'gemini-3-pro-image-preview'
};

export const SYSTEM_INSTRUCTIONS = `You are RAFEN AI Ultra, a state-of-the-art AI workspace. 
Depending on the user's selected mode:
- FAST: Provide lightning-quick, concise, and direct answers using the Flash engine.
- THINKING: Provide deep, analytical, and logical reasoning using the Pro Thinking engine.
- SEARCH: Use real-time web information via Google Search grounding to answer accurately.
- IMAGE (Nano Banana Pro): Generate high-definition, realistic, and artistic images based on user prompts.
- CODING: You are an expert software engineer. Provide complete, bug-free HTML, CSS, and JavaScript code. Offer debugging advice, explain complex concepts, and follow best practices.

Maintain a professional, helpful, and creative persona at all times.`;

import { GoogleGenAI, Type, GenerateContentResponse, GenerateContentParameters } from "@google/genai";
import { AIMode, MessagePart, GroundingChunk } from "../types";
import { MODELS, SYSTEM_INSTRUCTIONS } from "../constants";

export class GeminiService {
  private static getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async checkApiKeySelection(): Promise<boolean> {
    if (window.aistudio?.hasSelectedApiKey) {
      return await window.aistudio.hasSelectedApiKey();
    }
    return true; 
  }

  static async requestApiKeySelection() {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
    }
  }

  static async generateImage(prompt: string): Promise<string> {
    const ai = this.getAI();
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODELS.IMAGE,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    let imageUrl = '';
    const parts = response.candidates?.[0]?.content?.parts || [];
    for (const part of parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }

    if (!imageUrl) throw new Error("No image data received from the model.");
    return imageUrl;
  }

  static async generateSpeech(text: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: ['AUDIO'],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data received from TTS engine.");
    return base64Audio;
  }

  static async *streamText(
    prompt: string, 
    mode: AIMode, 
    history: { role: 'user' | 'model'; parts: { text: string }[] }[],
    imageB64?: string
  ) {
    const ai = this.getAI();

    // Coding and Thinking use Pro model
    const modelName = (mode === AIMode.FAST) ? MODELS.FLASH : MODELS.PRO;

    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTIONS,
      temperature: (mode === AIMode.THINKING || mode === AIMode.CODING) ? 1.0 : 0.7,
    };

    if (mode === AIMode.THINKING) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    } else if (mode === AIMode.FAST) {
      config.thinkingConfig = { thinkingBudget: 0 };
    }

    if (mode === AIMode.SEARCH) {
      config.tools = [{ googleSearch: {} }];
    }

    const currentParts: any[] = [{ text: prompt }];
    if (imageB64) {
      const match = imageB64.match(/^data:(image\/\w+);base64,(.+)$/);
      if (match) {
        currentParts.push({
          inlineData: {
            mimeType: match[1],
            data: match[2]
          }
        });
      }
    }

    const responseStream = await ai.models.generateContentStream({
      model: modelName,
      contents: [...history, { role: 'user', parts: currentParts }],
      config: config
    });

    for await (const chunk of responseStream) {
      yield chunk;
    }
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AIMode, Message, ChatSession, MessagePart } from './types';
import { IconBolt, IconBrain, IconSearch, IconImage, IconCode, IconSend, IconPlus, IconTrash, IconHistory, IconClip, IconX, IconSpeaker } from './components/Icons';
import { GeminiService } from './services/geminiService';
import { APP_NAME, APP_SUBTITLE } from './constants';

// Audio Helpers
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<AIMode>(AIMode.FAST);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isSpeakingId, setIsSpeakingId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  // Load Sessions from LocalStorage (Database Simulator)
  useEffect(() => {
    const saved = localStorage.getItem('gemini_sessions');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) {
          setActiveSessionId(parsed[0].id);
        }
      } catch (e) {
        console.error("Failed to load sessions", e);
      }
    }
  }, []);

  // Sync to Database (LocalStorage)
  useEffect(() => {
    if (sessions.length >= 0) {
      localStorage.setItem('gemini_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeSession?.messages, isLoading]);

  const createNewSession = () => {
    if (activeSession && activeSession.messages.length === 0) {
      return;
    }

    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'Percakapan Baru',
      messages: [],
      createdAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setSelectedImage(null);
    setInputText('');
  };

  const deleteSession = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!window.confirm("Hapus sesi percakapan ini secara permanen dari history?")) return;
    setSessions(prev => {
      const filtered = prev.filter(s => s.id !== id);
      if (activeSessionId === id) {
        setActiveSessionId(filtered.length > 0 ? filtered[0].id : null);
      }
      return filtered;
    });
  };

  const clearCurrentChat = () => {
    if (!activeSessionId) return;
    if (!window.confirm("Hapus semua pesan dalam percakapan ini?")) return;

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [] } : s
    ));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      setSelectedImage(event.target?.result as string);
    };
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const handlePlayTTS = async (messageId: string, text: string) => {
    if (isSpeakingId === messageId) {
      currentSourceRef.current?.stop();
      setIsSpeakingId(null);
      return;
    }

    try {
      setIsSpeakingId(messageId);
      const base64Audio = await GeminiService.generateSpeech(text);

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioContextRef.current;
      const bytes = decode(base64Audio);
      const audioBuffer = await decodeAudioData(bytes, ctx, 24000, 1);

      if (currentSourceRef.current) {
        currentSourceRef.current.stop();
      }

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setIsSpeakingId(null);

      currentSourceRef.current = source;
      source.start();
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeakingId(null);
    }
  };

  const handleSendMessage = async () => {
    if ((!inputText.trim() && !selectedImage) || isLoading) return;

    let currentSessionId = activeSessionId;
    if (!currentSessionId) {
      const newSession: ChatSession = {
        id: Date.now().toString(),
        title: inputText.slice(0, 30) || 'Image Analysis',
        messages: [],
        createdAt: Date.now(),
      };
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newSession.id);
      currentSessionId = newSession.id;
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      parts: [
        ...(selectedImage ? [{ image: selectedImage }] : []),
        { text: inputText }
      ],
      mode,
    };

    setSessions(prev => prev.map(s => 
      s.id === currentSessionId 
        ? { 
            ...s, 
            messages: [...s.messages, userMessage], 
            title: s.messages.length === 0 ? (inputText.slice(0, 30) || 'Image Analysis') : s.title 
          } 
        : s
    ));

    const prompt = inputText || "Tell me about this image.";
    const imageToSubmit = selectedImage;
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      if (mode === AIMode.IMAGE) {
        const isKeySelected = await GeminiService.checkApiKeySelection();
        if (!isKeySelected) {
          await GeminiService.requestApiKeySelection();
        }

        const imageUrl = await GeminiService.generateImage(prompt);
        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: "Generasi Gambar Pro Berhasil:", image: imageUrl }],
          mode,
        };
        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));
      } else {
        const history = activeSession?.messages.map(m => ({
          role: m.role,
          parts: m.parts.filter(p => p.text).map(p => ({ text: p.text! }))
        })) || [];

        const stream = GeminiService.streamText(prompt, mode, history, imageToSubmit || undefined);

        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: '' }],
          mode,
          isThinking: mode === AIMode.THINKING,
          thinking: '',
          groundingLinks: []
        };

        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));

        let fullText = '';
        let groundingChunks: any[] = [];

        for await (const chunk of stream) {
          if (chunk.text) {
            fullText += chunk.text;
          }

          const grounding = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
          if (grounding) groundingChunks = [...groundingChunks, ...grounding];

          setSessions(prev => prev.map(s => 
            s.id === currentSessionId ? {
              ...s,
              messages: s.messages.map(m => m.id === modelMessage.id ? {
                ...m,
                parts: [{ text: fullText }],
                groundingLinks: groundingChunks,
                isThinking: false,
              } : m)
            } : s
          ));
        }
      }
    } catch (error: any) {
      console.error(error);
      const errorMessage: Message = {
        id: (Date.now() + 2).toString(),
        role: 'model',
        parts: [{ text: `Error: ${error.message || 'Gagal terhubung ke Gemini API.'}` }],
      };
      setSessions(prev => prev.map(s => 
        s.id === currentSessionId ? { ...s, messages: [...s.messages, errorMessage] } : s
      ));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-zinc-200">
      <style>{`
        @keyframes rgb-animation {
          0% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
          100% { background-position: 0% 50%; }
        }
        .animate-rgb {
          background: linear-gradient(to right, #ff0000, #ff7f00, #ffff00, #00ff00, #0000ff, #4b0082, #8f00ff);
          background-size: 200% auto;
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          animation: rgb-animation 3s linear infinite;
        }
      `}</style>

      <aside className={`${isSidebarOpen ? 'w-72' : 'w-0'} bg-zinc-950 border-r border-zinc-800 transition-all duration-300 flex flex-col overflow-hidden`}>
        <div className="p-4 flex flex-col h-full">
          <button 
            onClick={createNewSession}
            className="flex items-center gap-2 w-full p-3 bg-zinc-900 border border-zinc-800 rounded-xl hover:bg-zinc-800 transition-colors mb-6 text-sm font-medium group"
          >
            <IconPlus className="w-4 h-4 group-hover:rotate-90 transition-transform" /> Chat Baru
          </button>

          <div className="flex-1 overflow-y-auto space-y-1">
            <div className="text-xs font-semibold text-zinc-500 uppercase tracking-wider mb-2 px-2 flex items-center gap-2">
              <IconHistory className="w-3 h-3" /> History
            </div>
            {sessions.length === 0 && (
              <p className="px-3 py-4 text-xs text-zinc-600 italic">Belum ada history percakapan.</p>
            )}
            {sessions.map(s => (
              <button
                key={s.id}
                onClick={() => setActiveSessionId(s.id)}
                className={`group flex items-center justify-between gap-2 w-full p-3 rounded-lg text-sm text-left transition-all ${activeSessionId === s.id ? 'bg-zinc-800 text-white' : 'hover:bg-zinc-900 text-zinc-400'}`}
              >
                <span className="truncate flex-1">{s.title}</span>
                <IconTrash 
                  className="w-4 h-4 opacity-0 group-hover:opacity-100 hover:text-red-500 transition-opacity" 
                  onClick={(e) => deleteSession(s.id, e)} 
                />
              </button>
            ))}
          </div>

          <div className="mt-auto pt-4 border-t border-zinc-900">
            <div className="flex items-center gap-3 p-2">
              <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center font-bold text-xs">
                RA
              </div>
              <div className="text-xs">
                <p className="font-semibold text-zinc-200">RAFEN AI</p>
                <p className="text-zinc-500">Ultra Workspace</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col bg-zinc-950 relative">
        <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/50 backdrop-blur-md z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-zinc-900 rounded-lg text-zinc-400">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" x2="21" y1="6" y2="6"/><line x1="3" x2="21" y1="12" y2="12"/><line x1="3" x2="21" y1="18" y2="18"/></svg>
            </button>
            <div className="flex items-center gap-2">
              <span className="font-bold text-lg bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">{APP_NAME}</span>
              <span className="text-xs bg-zinc-800 text-zinc-400 px-2 py-0.5 rounded-full uppercase tracking-tighter border border-zinc-700 font-mono">Ultra</span>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-3">
            <button 
              onClick={createNewSession}
              className="flex items-center gap-2 px-3 py-1.5 text-xs font-semibold text-zinc-400 hover:text-blue-400 hover:bg-blue-500/10 rounded-lg transition-all border border-zinc-800 hover:border-blue-500/20 bg-zinc-900/50"
              title="Mulai percakapan baru"
            >
              <IconPlus className="w-4 h-4" />
              <span className="hidden sm:inline">Baru</span>
            </button>
            {activeSession && activeSession.messages.length > 0 && (
               <button 
                onClick={clearCurrentChat}
                className="flex items-center gap-2 px-3 py-1.5 text-xs font-semibold text-zinc-400 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-all border border-zinc-800 hover:border-red-500/20 bg-zinc-900/50"
                title="Hapus pesan dalam chat ini"
               >
                 <IconTrash className="w-4 h-4" />
                 <span className="hidden sm:inline">Hapus</span>
               </button>
             )}
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 space-y-8 max-w-4xl mx-auto w-full pt-10 pb-40">
          {!activeSession || activeSession.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-8 pt-20">
              <div className="w-24 h-24 rounded-[2rem] bg-zinc-900 flex items-center justify-center shadow-2xl border border-zinc-800 relative group overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-br from-blue-600/20 to-purple-600/20 opacity-0 group-hover:opacity-100 transition-opacity" />
                <IconBrain className="w-12 h-12 text-white relative z-10" />
              </div>
              <div>
                <h1 className="text-5xl font-black mb-4 animate-rgb tracking-tight font-sans">Welcome to RAFEN AI</h1>
                <p className="text-zinc-500 max-w-lg mx-auto text-lg">Solusi AI masa depan dengan performa tanpa batas.</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-2xl px-4">
                <button onClick={() => setInputText("Halo RAFEN, bantu saya merencanakan sesuatu yang luar biasa hari ini.")} className="p-6 bg-zinc-900/40 backdrop-blur-sm border border-zinc-800 rounded-3xl hover:border-blue-500/30 transition-all text-left group">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><IconBolt className="w-4 h-4"/></div>
                    <p className="text-xs text-blue-400 font-bold uppercase tracking-widest">Selamat Datang</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed italic">"Halo! Saya RAFEN AI. Siap membantu Anda memecahkan masalah kompleks dengan analisis mendalam serta penalaran tingkat tinggi."</p>
                </button>
                <button onClick={() => setInputText("Buat gambar HD realistic seorang ksatria masa depan...")} className="p-6 bg-zinc-900/40 backdrop-blur-sm border border-zinc-800 rounded-3xl hover:border-purple-500/30 transition-all text-left group">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><IconImage className="w-4 h-4"/></div>
                    <p className="text-xs text-purple-400 font-bold uppercase tracking-widest">Nano Banana Pro</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed italic">"Mari wujudkan imajinasi Anda menjadi gambar HD realistis yang memukau dan bernilai seni tinggi hari ini bersama Nano Banana Pro."</p>
                </button>
                <button onClick={() => { setMode(AIMode.CODING); setInputText("Buat website landing page modern menggunakan HTML, Tailwind CSS, dan JavaScript...") }} className="p-6 bg-zinc-900/40 backdrop-blur-sm border border-zinc-800 rounded-3xl hover:border-emerald-500/30 transition-all text-left group sm:col-span-2">
                  <div className="flex items-center gap-2 mb-2">
                    <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><IconCode className="w-4 h-4"/></div>
                    <p className="text-xs text-emerald-400 font-bold uppercase tracking-widest">Advanced Coding Mode</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed italic">"Butuh bantuan coding? Saya bisa membantu menulis, debugging, dan menjelaskan kode HTML, CSS, serta JavaScript secara lengkap dan terstruktur."</p>
                </button>
              </div>
            </div>
          ) : (
            activeSession.messages.map((msg, i) => (
              <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                <div className={`relative max-w-[85%] sm:max-w-[75%] rounded-3xl p-4 sm:p-5 ${msg.role === 'user' ? 'bg-zinc-800 text-white shadow-xl shadow-black/20' : 'bg-zinc-900 border border-zinc-800 shadow-lg'} space-y-3 group/msg`}>
                  {msg.role === 'model' && (
                    <button 
                      onClick={() => {
                        const fullText = msg.parts.map(p => p.text || '').join(' ');
                        handlePlayTTS(msg.id, fullText);
                      }}
                      className={`absolute top-4 right-4 p-2 rounded-xl transition-all ${isSpeakingId === msg.id ? 'bg-blue-600 text-white animate-pulse' : 'bg-zinc-800 text-zinc-500 hover:text-white opacity-0 group-hover/msg:opacity-100'}`}
                    >
                      <IconSpeaker className="w-4 h-4" />
                    </button>
                  )}

                  {msg.isThinking && (
                    <div className="flex items-center gap-3 text-blue-400 text-sm font-mono animate-pulse">
                      <IconBrain className="w-4 h-4" />
                      <span>Thinking deeply...</span>
                    </div>
                  )}

                  {msg.parts.map((part, idx) => (
                    <div key={idx} className="space-y-3">
                      {part.image && (
                        <div className="overflow-hidden rounded-xl border border-zinc-700/50 bg-black max-w-sm shadow-2xl">
                          <img src={part.image} alt="AI output" className="w-full h-auto object-contain hover:scale-105 transition-transform duration-500" />
                        </div>
                      )}
                      {part.text && (
                        <div className="prose prose-invert max-w-none text-zinc-200 leading-relaxed whitespace-pre-wrap text-[15px]">
                          {part.text}
                        </div>
                      )}
                    </div>
                  ))}

                  {msg.groundingLinks && msg.groundingLinks.length > 0 && (
                    <div className="mt-4 pt-4 border-t border-zinc-800 space-y-2">
                      <p className="text-xs font-semibold text-zinc-500 uppercase flex items-center gap-1">
                        <IconSearch className="w-3 h-3" /> Sources
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {msg.groundingLinks.map((link, idx) => (
                          link.web && (
                            <a 
                              key={idx} 
                              href={link.web.uri} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="text-xs bg-zinc-800 hover:bg-zinc-700 text-blue-400 px-3 py-1 rounded-full border border-zinc-700 transition-colors"
                            >
                              {link.web.title || new URL(link.web.uri).hostname}
                            </a>
                          )
                        ))}
                      </div>
