          </button>
          <div className="flex-1 overflow-y-auto space-y-1">
            <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 px-2">Recent Intelligence</p>
            {sessions.map(s => (
              <button key={s.id} onClick={() => setActiveSessionId(s.id)} className={`group flex items-center justify-between gap-3 w-full p-3.5 rounded-xl text-sm text-left transition-all ${activeSessionId === s.id ? 'bg-zinc-800/80 text-white shadow-lg border border-zinc-700/50' : 'hover:bg-zinc-900/50 text-zinc-500 hover:text-zinc-300'}`}>
