          role: m.role,
          parts: m.parts.filter(p => p.text).map(p => ({ text: p.text! }))
        })) || [];

        const stream = GeminiService.streamText(promptText, mode, history, imageToSubmit || undefined);
        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
