            s.id === currentSessionId ? {
              ...s,
              messages: s.messages.map(m => m.id === modelMessage.id ? {
                ...m,
                parts: [{ text: fullText }],
                groundingLinks: groundingChunks,
                isThinking: false,
              } : m)
            } : s
          ));
        }
      }
    } catch (error: any) {
      console.error(error);
      const is403 = error.message?.includes("403") || error.message?.includes("PERMISSION_DENIED");
