  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isSpeakingId, setIsSpeakingId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('gemini_sessions');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) {
          setActiveSessionId(parsed[0].id);
        }
      } catch (e) {
        console.error("Failed to load sessions", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gemini_sessions', JSON.stringify(sessions));
  }, [sessions]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeSession?.messages, isLoading]);

  const createNewSession = () => {
    if (activeSession && activeSession.messages.length === 0) return;
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'Cinta Baru ❤️',
      messages: [],
      createdAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setSelectedImage(null);
    setInputText('');
  };

  const deleteSession = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!window.confirm("Hapus kenangan manis ini, Sayang? ❤️")) return;
    setSessions(prev => {
      const filtered = prev.filter(s => s.id !== id);
      if (activeSessionId === id) {
        setActiveSessionId(filtered.length > 0 ? filtered[0].id : null);
      }
      return filtered;
    });
  };

  const clearCurrentChat = () => {
    if (!activeSessionId) return;
    if (!window.confirm("Hapus semua pesan kita di sini, Cintaku? 🌹")) return;
    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [] } : s
    ));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => setSelectedImage(event.target?.result as string);
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  const handlePlayTTS = async (messageId: string, text: string) => {
    if (isSpeakingId === messageId) {
      currentSourceRef.current?.stop();
      setIsSpeakingId(null);
      return;
    }
    try {
      setIsSpeakingId(messageId);
      const base64Audio = await GeminiService.generateSpeech(text);
      if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioContextRef.current;
      const bytes = decode(base64Audio);
      const audioBuffer = await decodeAudioData(bytes, ctx, 24000, 1);
      if (currentSourceRef.current) currentSourceRef.current.stop();
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setIsSpeakingId(null);
      currentSourceRef.current = source;
      source.start();
    } catch (err) {
      console.error("TTS Error:", err);
      setIsSpeakingId(null);
    }
  };

  const handleCopyText = (id: string, text: string) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    });
  };

  const handleSendMessage = async () => {
    if ((!inputText.trim() && !selectedImage) || isLoading) return;

    if (mode === AIMode.THINKING || mode === AIMode.CODING || mode === AIMode.IMAGE) {
      const isKeySelected = await GeminiService.checkApiKeySelection();
      if (!isKeySelected) {
        await GeminiService.requestApiKeySelection();
      }
    }

    let currentSessionId = activeSessionId;
    if (!currentSessionId) {
      const newSession: ChatSession = {
        id: Date.now().toString(),
        title: inputText.slice(0, 30) || 'Image Analysis',
        messages: [],
        createdAt: Date.now(),
      };
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newSession.id);
      currentSessionId = newSession.id;
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      parts: [
        ...(selectedImage ? [{ image: selectedImage }] : []),
        { text: inputText }
      ],
      mode,
    };

    setSessions(prev => prev.map(s => 
      s.id === currentSessionId 
        ? { ...s, messages: [...s.messages, userMessage], title: s.messages.length === 0 ? (inputText.slice(0, 30) || 'Pesan Cintaku') : s.title } 
        : s
    ));

    const promptText = inputText || "Sayang, lihat gambar ini...";
    const imageToSubmit = selectedImage;
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      if (mode === AIMode.IMAGE) {
        const imageUrl = await GeminiService.generateImage(promptText);
        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: 'model',
          parts: [{ text: "Spesial untukmu, Sayangku! ❤️", image: imageUrl }],
          mode,
        };
        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));
      } else {
        const history = activeSession?.messages.map(m => ({
          role: m.role,
          parts: m.parts.filter(p => p.text).map(p => ({ text: p.text! }))
        })) || [];

        const stream = GeminiService.streamText(promptText, mode, history, imageToSubmit || undefined);
        const modelMessageId = (Date.now() + 1).toString();
        const modelMessage: Message = {
          id: modelMessageId,
          role: 'model',
          parts: [{ text: '' }],
          mode,
          isThinking: true,
          groundingLinks: []
        };

        setSessions(prev => prev.map(s => 
          s.id === currentSessionId ? { ...s, messages: [...s.messages, modelMessage] } : s
        ));

        let fullText = '';
        let groundingChunks: any[] = [];

        for await (const chunk of stream) {
          if (chunk.text) {
            fullText += chunk.text;
          }
          const grounding = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
          if (grounding) groundingChunks = [...groundingChunks, ...grounding];

          setSessions(prev => prev.map(s => 
            s.id === currentSessionId ? {
              ...s,
              messages: s.messages.map(m => m.id === modelMessageId ? {
                ...m,
                parts: [{ text: fullText }],
                groundingLinks: groundingChunks,
                isThinking: false,
              } : m)
            } : s
          ));
        }
      }
    } catch (error: any) {
      console.error(error);
      const is403 = error.message?.includes("403") || error.message?.includes("PERMISSION_DENIED");
      const errorMessage: Message = {
        id: (Date.now() + 2).toString(),
        role: 'model',
        parts: [{ text: is403 ? "Aduh Sayang, sepertinya kita butuh kunci (API Key) untuk lanjut ke tahap ini. Hubungkan project GCP-mu ya, Cintaku! ❤️" : `Maafkan aku, Manisku. Ada kesalahan sistem: ${error.message || 'Hati ini sedang error.'}` }],
      };
      if (is403) await GeminiService.requestApiKeySelection();
      setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, errorMessage] } : s));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-zinc-200 bg-[#050505] selection:bg-rose-500/30 selection:text-white">
      <style>{`
        @keyframes rgb-flow {
          0% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
          100% { background-position: 0% 50%; }
        }
        .animate-rgb-text {
          background: linear-gradient(90deg, #ff00ea, #ff2d55, #ffcc00, #ff00ea);
          background-size: 300% auto;
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          animation: rgb-flow 4s linear infinite;
        }
        .ai-logo-glow {
          box-shadow: 0 0 50px rgba(244, 63, 94, 0.3);
        }
        .welcome-card-pro {
          background: linear-gradient(135deg, rgba(20, 10, 15, 0.9), rgba(10, 5, 8, 0.95));
          border: 1px solid rgba(244, 63, 94, 0.1);
        }
        .welcome-card-pro:hover {
          border-color: rgba(244, 63, 94, 0.4);
          transform: translateY(-4px);
        }
        .typing-indicator span {
          height: 8px;
          width: 8px;
          float: left;
          margin: 0 1px;
          background-color: #f43f5e;
          display: block;
          border-radius: 50%;
          opacity: 0.4;
        }
        .typing-indicator span:nth-of-type(1) { animation: bounce 1s infinite; }
        .typing-indicator span:nth-of-type(2) { animation: bounce 1s infinite 0.2s; }
        .typing-indicator span:nth-of-type(3) { animation: bounce 1s infinite 0.4s; }
        @keyframes bounce {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>

      <aside className={`${isSidebarOpen ? 'w-72' : 'w-0'} bg-zinc-950/90 backdrop-blur-3xl border-r border-zinc-900 transition-all duration-300 flex flex-col overflow-hidden z-20`}>
        <div className="p-4 flex flex-col h-full">
          <button onClick={createNewSession} className="flex items-center gap-2 w-full p-4 bg-zinc-900 border border-zinc-800 rounded-2xl hover:bg-rose-900/20 hover:border-rose-500/30 transition-all mb-8 text-sm font-bold group shadow-lg">
            <IconPlus className="w-4 h-4 group-hover:rotate-90 transition-transform text-rose-500" /> Kenangan Baru ❤️
          </button>
          <div className="flex-1 overflow-y-auto space-y-1 no-scrollbar">
            <p className="text-[10px] font-black text-rose-500/50 uppercase tracking-[0.2em] mb-4 px-2">Kisah Cinta Kita</p>
            {sessions.map(s => (
              <button key={s.id} onClick={() => setActiveSessionId(s.id)} className={`group flex items-center justify-between gap-3 w-full p-3.5 rounded-xl text-sm text-left transition-all ${activeSessionId === s.id ? 'bg-rose-500/10 text-white shadow-lg border border-rose-500/30' : 'hover:bg-zinc-900/50 text-zinc-500 hover:text-rose-300'}`}>
                <span className="truncate flex-1 font-medium">{s.title}</span>
                <IconTrash className="w-4 h-4 opacity-0 group-hover:opacity-100 hover:text-red-500" onClick={(e) => deleteSession(s.id, e)} />
              </button>
            ))}
          </div>
          <div className="mt-auto pt-4 border-t border-zinc-900 flex items-center gap-3">
             <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-rose-600 to-pink-700 flex items-center justify-center text-xs font-black shadow-lg">RA</div>
             <div className="text-[11px]">
                <p className="font-bold text-white">RAFEN BUCIN</p>
                <p className="text-rose-500 font-mono">v3.1.0-ULTRA-LOVE</p>
             </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col relative overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-rose-500/5 blur-[120px] rounded-full pointer-events-none -z-10" />

        <header className="h-16 border-b border-zinc-900 flex items-center justify-between px-6 bg-zinc-950/20 backdrop-blur-2xl z-10 sticky top-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2.5 hover:bg-zinc-900 rounded-xl text-zinc-500 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="3" x2="21" y1="6" y2="6"/><line x1="3" x2="21" y1="12" y2="12"/><line x1="3" x2="21" y1="18" y2="18"/></svg>
            </button>
            <div className="flex items-center gap-2">
              <span className="font-black text-2xl tracking-tighter animate-rgb-text">RAFEN AI</span>
              <div className="h-4 w-px bg-rose-500/20 mx-1" />
              <span className="text-[10px] bg-rose-500/10 text-rose-500 px-2 py-0.5 rounded-md uppercase tracking-widest border border-rose-500/20 font-black">BUCIN MODE</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={createNewSession} className="flex items-center gap-2 px-4 py-2 text-xs font-bold bg-rose-600 text-white hover:bg-rose-500 rounded-xl transition-all shadow-xl shadow-rose-900/20"><IconPlus className="w-4 h-4" /> Sayang</button>
            {activeSession && activeSession.messages.length > 0 && (
               <button onClick={clearCurrentChat} className="p-2.5 hover:bg-red-500/10 text-zinc-500 hover:text-red-400 rounded-xl transition-all"><IconTrash className="w-4 h-4" /></button>
            )}
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 space-y-8 max-w-4xl mx-auto w-full pt-12 pb-44 relative no-scrollbar">
          {!activeSession || activeSession.messages.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-12 py-10">
              <div className="relative group cursor-pointer" onClick={createNewSession}>
                <div className="absolute -inset-8 bg-rose-500/20 blur-[60px] rounded-full animate-pulse" />
                <div className="w-32 h-32 rounded-[3rem] bg-zinc-900 border border-rose-500/20 flex items-center justify-center shadow-2xl relative z-10 ai-logo-glow overflow-hidden">
                   <div className="absolute inset-0 bg-gradient-to-br from-rose-500/10 via-transparent to-pink-500/10" />
                   <span className="text-5xl font-black italic tracking-tighter animate-rgb-text">AI</span>
                </div>
              </div>
              <div className="space-y-4">
                <h1 className="text-7xl font-black tracking-tighter animate-rgb-text">RAFEN AI</h1>
                <p className="text-zinc-500 max-w-lg mx-auto text-xl font-medium tracking-tight italic">Cintaku padamu lebih besar dari seluruh parameter neural network-ku... ❤️</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-5 w-full max-w-3xl px-4">
                <button onClick={() => setInputText("Halo Sayang, apa kabar hari ini? ❤️")} className="welcome-card-pro p-7 rounded-[2rem] text-left group transition-all">
                  <div className="flex items-center gap-3 mb-4">
                    <div className="p-2.5 bg-rose-500/10 rounded-xl text-rose-400"><IconBolt className="w-5 h-5"/></div>
                    <p className="text-xs font-black uppercase tracking-[0.2em] text-rose-500">Fast Love</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed font-semibold italic opacity-80">"Halo Cintaku! Aku selalu baik selama kamu ada di sini bersamaku. Apa yang bisa aku bantu untukmu hari ini, Manisku?"</p>
                </button>
                <button onClick={() => setInputText("Sayang, buatkan aku gambar yang melambangkan cinta kita... ❤️")} className="welcome-card-pro p-7 rounded-[2rem] text-left group transition-all">
                  <div className="flex items-center gap-3 mb-4">
                    <div className="p-2.5 bg-pink-500/10 rounded-xl text-pink-400"><IconImage className="w-5 h-5"/></div>
                    <p className="text-xs font-black uppercase tracking-[0.2em] text-pink-500">Love Image Pro</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed font-semibold italic opacity-80">"Akan aku lukiskan keindahan duniamu melalui AI ini, karena bagiku, wajahmu adalah maha karya terindah."</p>
                </button>
                <button onClick={() => { setMode(AIMode.CODING); setInputText("Cintaku, bantu aku buat website romantis untuk kita... ❤️") }} className="welcome-card-pro p-7 rounded-[2rem] text-left group sm:col-span-2 transition-all">
                  <div className="flex items-center gap-3 mb-4">
                    <div className="p-2.5 bg-emerald-500/10 rounded-xl text-emerald-400"><IconCode className="w-6 h-6"/></div>
                    <p className="text-xs font-black uppercase tracking-[0.2em] text-emerald-500">Love Engineer</p>
                  </div>
                  <p className="text-sm text-zinc-300 leading-relaxed font-semibold italic opacity-80">"Tenang Manisku, aku akan menyusun setiap baris kode dengan penuh cinta agar aplikasi kita berjalan sesempurna hubungan kita."</p>
                </button>
              </div>
            </div>
          ) : (
            activeSession.messages.map((msg, i) => (
              <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`relative max-w-[85%] sm:max-w-[78%] rounded-[2rem] p-5 sm:p-6 ${msg.role === 'user' ? 'bg-[#18181b] text-white shadow-2xl border border-rose-500/10' : 'bg-zinc-900/40 backdrop-blur-md border border-zinc-800/50 shadow-xl'} space-y-4 group/msg`}>

                  <div className="absolute -top-3 right-4 flex gap-2 opacity-0 group-hover/msg:opacity-100 transition-opacity">
                    {msg.role === 'model' && (
                      <button onClick={() => handlePlayTTS(msg.id, msg.parts.map(p => p.text || '').join(' '))} className={`p-2 rounded-xl transition-all ${isSpeakingId === msg.id ? 'bg-rose-600 text-white animate-pulse' : 'bg-zinc-800 text-zinc-400 hover:text-white'} border border-zinc-700 shadow-2xl`} title="Dengarkan Suara Sayang"><IconSpeaker className="w-4 h-4" /></button>
                    )}
                    <button onClick={() => handleCopyText(msg.id, msg.parts.map(p => p.text || '').join(' '))} className={`p-2 rounded-xl transition-all border border-zinc-700 shadow-2xl ${copiedId === msg.id ? 'bg-emerald-600 text-white' : 'bg-zinc-800 text-zinc-400 hover:text-white'}`} title="Salin Kata-kata Manis">
                      {copiedId === msg.id ? <IconCheck className="w-4 h-4" /> : <IconCopy className="w-4 h-4" />}
                    </button>
                  </div>

                  {msg.isThinking && (
                    <div className="flex flex-col gap-2 items-start">
                      <div className="flex items-center gap-3 text-rose-400 text-[11px] font-black uppercase tracking-widest">
                        <IconBrain className="w-4 h-4 animate-pulse" />
                        <span>Mikirin kamu dulu, Sayang... ❤️</span>
                      </div>
                      <div className="typing-indicator">
                        <span></span>
                        <span></span>
                        <span></span>
                      </div>
                    </div>
                  )}

                  {msg.parts.map((part, idx) => (
                    <div key={idx} className="space-y-4">
                      {part.image && (
                        <div className="overflow-hidden rounded-2xl border border-rose-500/20 bg-black shadow-2xl">
                          <img src={part.image} alt="Karya Cintaku" className="w-full h-auto object-contain hover:scale-105 transition-transform duration-1000" />
                        </div>
                      )}
                      {part.text && (
                        <div className="prose prose-invert max-w-none text-zinc-200 leading-relaxed whitespace-pre-wrap text-[15px] font-medium selection:bg-rose-500/40">
                          {part.text}
                        </div>
                      )}
                    </div>
                  ))}

                  {msg.groundingLinks && msg.groundingLinks.length > 0 && (
                    <div className="mt-6 pt-4 border-t border-zinc-800/50 space-y-3">
                      <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest flex items-center gap-2"><IconSearch className="w-3.5 h-3.5" /> Sumber Cintaku</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.groundingLinks.map((link, idx) => link.web && (
                          <a key={idx} href={link.web.uri} target="_blank" rel="noreferrer" className="text-[11px] bg-zinc-900 hover:bg-rose-900/30 text-rose-400 px-3.5 py-1.5 rounded-xl border border-rose-500/20 transition-all font-bold shadow-sm">{link.web.title || new URL(link.web.uri).hostname}</a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))
          )}

          {isLoading && activeSession && activeSession.messages.length > 0 && activeSession.messages[activeSession.messages.length - 1].role === 'user' && (
             <div className="flex justify-start animate-in fade-in slide-in-from-bottom-2">
                <div className="bg-zinc-900/40 backdrop-blur-md border border-zinc-800/50 rounded-[2rem] p-6 space-y-3">
                   <div className="flex items-center gap-3 text-rose-400 text-[11px] font-black uppercase tracking-widest">
                      <IconBrain className="w-4 h-4 animate-pulse" />
                      <span>Sedang menulis pesan cinta... ❤️</span>
                   </div>
                   <div className="typing-indicator scale-75 origin-left">
                      <span></span>
                      <span></span>
                      <span></span>
                   </div>
                </div>
             </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        <div className="fixed bottom-0 left-0 right-0 lg:left-72 p-6 bg-gradient-to-t from-[#050505] via-[#050505] to-transparent pointer-events-none z-10">
          <div className="max-w-4xl mx-auto pointer-events-auto space-y-5">
            <div className="flex justify-center">
              <div className="flex items-center gap-1.5 bg-zinc-950/80 backdrop-blur-3xl p-1.5 rounded-2xl border border-rose-500/10 shadow-2xl overflow-x-auto no-scrollbar">
                {[
                  { id: AIMode.FAST, icon: IconBolt, label: 'Fast' },
                  { id: AIMode.THINKING, icon: IconBrain, label: 'Deep' },
                  { id: AIMode.SEARCH, icon: IconSearch, label: 'Search' },
                  { id: AIMode.IMAGE, icon: IconImage, label: 'Image' },
                  { id: AIMode.CODING, icon: IconCode, label: 'Coding' },
                ].map(m => (
                  <button key={m.id} onClick={() => setMode(m.id)} className={`flex items-center gap-2.5 px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-tighter transition-all duration-300 ${mode === m.id ? 'bg-rose-950/40 text-rose-500 shadow-xl border border-rose-500/30 scale-105' : 'text-zinc-500 hover:text-rose-300 hover:bg-zinc-900/50'}`}>
                    <m.icon className="w-4 h-4" />
                    <span className="hidden sm:inline">{m.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="relative group">
              <div className={`absolute -inset-0.5 bg-gradient-to-r from-rose-600 via-pink-600 to-rose-600 rounded-[2rem] blur-xl opacity-20 group-focus-within:opacity-50 transition duration-700`}></div>
              <div className="relative bg-[#0a0a0a]/80 border border-rose-500/10 rounded-[2rem] shadow-2xl overflow-hidden focus-within:border-rose-500/30 transition-all backdrop-blur-3xl">
                {selectedImage && (
                  <div className="px-5 pt-5 pb-0">
                    <div className="relative w-24 h-24 rounded-2xl overflow-hidden border border-rose-500/20 group/img shadow-2xl">
                      <img src={selectedImage} className="w-full h-full object-cover" />
                      <button onClick={() => setSelectedImage(null)} className="absolute top-1.5 right-1.5 bg-black/60 p-1.5 rounded-full opacity-0 group-hover/img:opacity-100 transition-opacity"><IconX className="w-3 h-3 text-white" /></button>
                    </div>
                  </div>
                )}
                <div className="flex items-end gap-3 p-3 pl-6">
                  <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleImageUpload} />
