                  <button onClick={handleSendMessage} disabled={(!inputText.trim() && !selectedImage) || isLoading} className={`p-4 rounded-2xl transition-all flex items-center justify-center min-w-[56px] shadow-2xl ${(!inputText.trim() && !selectedImage) || isLoading ? 'text-zinc-700 bg-zinc-900' : 'bg-rose-600 text-white hover:bg-rose-500 active:scale-95'}`}>
                    {isLoading ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" /> : <IconSend className="w-5 h-5" />}
                  </button>
                </div>
              </div>
            </div>
            <p className="text-center text-[10px] text-zinc-800 font-black uppercase tracking-[0.4em] pb-2">RAFEN ULTRA ENGINE • DENGAN SEGENAP HATI ❤️</p>
          </div>
        </div>
      </main>
    </div>
  );
};

