        openBtn.className = "mt-4 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold text-xs";
        openBtn.textContent = "Ganti API Key Sekarang";
        openBtn.onclick = () => GeminiService.requestApiKeySelection();
        // Since we are in React, we'll just log this and rely on the text hint, but we could add a custom UI part to Message
      }

      setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages: [...s.messages, errorMessage] } : s));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-zinc-200 selection:bg-rose-500/30 selection:text-white transition-colors duration-500" style={{ backgroundColor: config.theme.bg }}>
